transcript.content:
[
  {
    "biasType": "Spin",
    "biasedText": "Kid Rock buried Puerto Rican rapper Bad Bunny in the gossip site TMZ's poll",
    "explanation": "The use of 'buried' is a dramatic, subjective verb that adds a sense of sensationalism and spin rather than neutrally reporting the poll result."
  },
  {
    "biasType": "Sensationalism/Emotionalism",
    "biasedText": "TMZ tried its best to lead its fans to pick Bad Bunny by characterizing the rabidly anti-Trump rapper's show as taking place on \"one of the world's biggest stages,\" while merely saying that Kid Rock \"tried to outshine\" Bad Bunny.",
    "explanation": "The language 'tried its best to lead its fans' attributes a manipulative intent to TMZ and phrases like 'rabidly anti-Trump' are emotionally charged, amplifying sensationalism and potentially stoking reader bias."
  },
  {
    "biasType": "Mind Reading",
    "biasedText": "The poll may not have gone exactly how TMZ expected",
    "explanation": "The author presumes to know TMZ's expectations without evidence, making an assumption about the intentions behind the poll."
  },
  {
    "biasType": "Omission of Source Attribution",
    "biasedText": "According to some of the latest statistics, it seems that nearly half of Super Bowl viewers tuned out of the league's Bad Bunny Halftime Show.",
    "explanation": "No specific source is cited for the claim about viewer numbers, making it unclear where this statistic comes from and reducing the verifiability of the statement."
  },
  {
    "biasType": "Subjective Qualifying Adjectives",
    "biasedText": "\"the rabidly anti-Trump rapper\"",
    "explanation": "The adjective 'rabidly' is a subjective, loaded descriptor that carries negative connotations, signaling an opinion about Bad Bunny's political stance rather than an objective description."
  }
]

